/**
 * Minimal Dexie-compatible IndexedDB Wrapper for Nextora POS Enterprise Offline Engine
 * Provides declarative store definitions, indexed querying, transaction support, and promises.
 */
(function (global) {
  'use strict';

  class DexieTable {
    constructor(dbName, tableName, schemaStr) {
      this.dbName = dbName;
      this.tableName = tableName;
      this.schemaStr = schemaStr;
      this._parseSchema(schemaStr);
    }

    _parseSchema(schemaStr) {
      const parts = schemaStr.split(',').map(s => s.trim()).filter(Boolean);
      this.primaryKey = null;
      this.autoIncrement = false;
      this.indexes = [];
      parts.forEach((p, idx) => {
        let name = p;
        if (p.startsWith('++')) {
          name = p.substring(2);
          if (idx === 0) {
            this.primaryKey = name;
            this.autoIncrement = true;
          }
        } else if (idx === 0) {
          this.primaryKey = name;
        }
        if (idx > 0) {
          this.indexes.push(name);
        }
      });
    }

    async _openDB() {
      return new Promise((resolve, reject) => {
        const req = indexedDB.open(this.dbName);
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
      });
    }

    async put(item) {
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readwrite');
        const store = tx.objectStore(this.tableName);
        const req = store.put(item);
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
        tx.oncomplete = () => db.close();
      });
    }

    async bulkPut(items) {
      if (!items || !items.length) return;
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readwrite');
        const store = tx.objectStore(this.tableName);
        items.forEach(item => store.put(item));
        tx.oncomplete = () => {
          db.close();
          resolve();
        };
        tx.onerror = () => reject(tx.error);
      });
    }

    async get(key) {
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readonly');
        const store = tx.objectStore(this.tableName);
        const req = store.get(key);
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
        tx.oncomplete = () => db.close();
      });
    }

    async toArray() {
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readonly');
        const store = tx.objectStore(this.tableName);
        const req = store.getAll();
        req.onsuccess = () => resolve(req.result || []);
        req.onerror = () => reject(req.error);
        tx.oncomplete = () => db.close();
      });
    }

    async where(indexName) {
      const self = this;
      return {
        equals: async (value) => {
          const db = await self._openDB();
          return new Promise((resolve, reject) => {
            const tx = db.transaction(self.tableName, 'readonly');
            const store = tx.objectStore(self.tableName);
            let req;
            if (indexName === self.primaryKey) {
              req = store.get(value);
              req.onsuccess = () => resolve(req.result ? [req.result] : []);
            } else if (store.indexNames.contains(indexName)) {
              const idx = store.index(indexName);
              req = idx.getAll(value);
              req.onsuccess = () => resolve(req.result || []);
            } else {
              req = store.getAll();
              req.onsuccess = () => {
                const filtered = (req.result || []).filter(row => row[indexName] === value);
                resolve(filtered);
              };
            }
            req.onerror = () => reject(req.error);
            tx.oncomplete = () => db.close();
          });
        }
      };
    }

    async count() {
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readonly');
        const store = tx.objectStore(this.tableName);
        const req = store.count();
        req.onsuccess = () => resolve(req.result || 0);
        req.onerror = () => reject(req.error);
        tx.oncomplete = () => db.close();
      });
    }

    async clear() {
      const db = await this._openDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.tableName, 'readwrite');
        const store = tx.objectStore(this.tableName);
        const req = store.clear();
        req.onsuccess = () => resolve();
        req.onerror = () => reject(req.error);
        tx.oncomplete = () => db.close();
      });
    }
  }

  class Dexie {
    constructor(dbName) {
      this.name = dbName;
      this.versionNumber = 1;
      this.storesSchema = {};
      this.tables = {};
    }

    version(num) {
      this.versionNumber = num;
      return this;
    }

    stores(schema) {
      this.storesSchema = schema;
      Object.keys(schema).forEach(tableName => {
        const tbl = new DexieTable(this.name, tableName, schema[tableName]);
        this.tables[tableName] = tbl;
        this[tableName] = tbl;
      });
      return this;
    }

    async open() {
      return new Promise((resolve, reject) => {
        const req = indexedDB.open(this.name, this.versionNumber);
        req.onupgradeneeded = (e) => {
          const db = e.target.result;
          Object.keys(this.storesSchema).forEach(tableName => {
            if (!db.objectStoreNames.contains(tableName)) {
              const tbl = this.tables[tableName];
              const opts = {};
              if (tbl.primaryKey) {
                opts.keyPath = tbl.primaryKey;
                if (tbl.autoIncrement) opts.autoIncrement = true;
              }
              const store = db.createObjectStore(tableName, opts);
              tbl.indexes.forEach(idx => {
                store.createIndex(idx, idx, { unique: false });
              });
            }
          });
        };
        req.onsuccess = () => {
          req.result.close();
          resolve(this);
        };
        req.onerror = () => reject(req.error);
      });
    }
  }

  global.Dexie = Dexie;
})(typeof window !== 'undefined' ? window : this);
